import type { Meta, StoryObj } from "@storybook/react";
import { useState } from "react";
import { Flex, Heading, TextField, Button } from "@vibe/core";

const LoginForm = () => {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");

  const handleSubmit = () => {
    alert(`Logging in with: Username - ${username}, Password - ${password}`);
  };

  return (
    <Flex direction="column" gap="large" style={{ width: 300, padding: 20, border: "1px solid #ccc", borderRadius: 8 }}>
      <Heading type="h1" weight="bold">
        Login
      </Heading>
      <TextField
        title="Username"
        placeholder="Enter your username"
        value={username}
        onChange={setUsername}
      />
      <TextField
        title="Password"
        placeholder="Enter your password"
        type="password"
        value={password}
        onChange={setPassword}
      />
      <Button onClick={handleSubmit}>
        Login
      </Button>
    </Flex>
  );
};

const meta: Meta<typeof LoginForm> = {
  title: "AI Drafts/TestDebug",
  component: LoginForm,
};

